function icon(name){ return (window.ICONS && window.ICONS[name]) || ''; }

// Fill any static <... data-icon="name"> placeholders
function hydrateIcons(root){
  (root||document).querySelectorAll('[data-icon]').forEach(function(el){
    if(el.dataset.iconDone) return;
    var svg = icon(el.getAttribute('data-icon'));
    if(svg){ el.innerHTML = svg; el.dataset.iconDone = '1'; }
  });
}
if(document.readyState === 'loading'){
  document.addEventListener('DOMContentLoaded', function(){ hydrateIcons(document); });
} else { hydrateIcons(document); }
